const readline = require('readline');

function main() {
    const rl = readline.createInterface({
        input: process.stdin,
        output: process.stdout
    });

    let inputLines = [];

    rl.on('line', (line) => {
        inputLines.push(line);
        if (inputLines.length === 2) {
            rl.close();
        }
    });

    rl.on('close', () => {
        // Extract the number of elements and the elements of the array
        let n = parseInt(inputLines[0]);
        let array = inputLines[1].split(' ').map(Number);

        // Initialize smallest and largest values
        let smallest = Infinity;
        let largest = -Infinity;

        // Iterate through the array to find the smallest and largest elements
        for (let num of array) {
            if (num < smallest) {
                smallest = num;
            }
            if (num > largest) {
                largest = num;
            }
        }

        // Print the smallest and largest values
        console.log(smallest, largest);
    });
}

